INSERT INTO styles (name, category, style_id, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, ebc_min, ebc_max, abv_min, abv_max, notes, aroma, appearance, flavor, mouthfeel) VALUES ('Ordinary Bitter', 'British Origin Ale Styles', '93F5021C-E70A-40BF-8425-4F2D900E6170', 1.033, 1.038, 1.006, 1.012, 20, 35, 10, 24, 2.4, 3.3, 'Mild carbonation traditionally characterizes draft-cask versions, but in bottled versions, a slight increase in carbon dioxide content is acceptable. Fruity esters are acceptable. Diacetyl is usually absent in these beers but may be present at low levels.When using these guidelines as the basis for evaluating entries at competitions, competition organizers may choose to create subcategories which reflect English and American hop character.', 'Very low to medium-low 
Low to medium residual malt sweetness should be present', 'Chill haze is allowable at cold temperatures', 'Very low to medium-low 
Low to medium residual malt sweetness should be present', 'Low to medium');
