INSERT INTO styles (name, category, style_id, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, ebc_min, ebc_max, abv_min, abv_max, notes, aroma, appearance, flavor, mouthfeel) VALUES ('Bamberg-Style Helles Rauchbier', 'European Origin Lager Styles', '8E20C018-785A-4C04-A0E2-F3DFDED4A8BE', 1.044, 1.05, 1.008, 1.012, 18, 25, 8, 11, 3.8, 4.4, 'Fruity esters and diacetyl should not be present. Very low levels of sulfur-related compounds are acceptable.', 'Hop aroma and ﬂavor is very low to low, derived from noble-type hops. 
