INSERT INTO styles (name, category, style_id, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, ebc_min, ebc_max, abv_min, abv_max, notes, aroma, appearance, flavor, mouthfeel) VALUES ('Bamberg-Style Maerzen Rauchbier', 'European Origin Lager Styles', '1E919964-A8D5-49C6-A7AF-373E5702ADEE', 1.05, 1.06, 1.012, 1.02, 18, 25, 8, 30, 4, 4.7, 'Fruity esters and diacetyl should not be present', 'Hop aroma and ﬂavor is very low to low, derived from noble-type hops. 
