INSERT INTO styles (name, category, style_id, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, ebc_min, ebc_max, abv_min, abv_max, notes, aroma, appearance, flavor, mouthfeel) VALUES ('German-Style Doppelbock', 'European Origin Lager Styles', '7C6B376F-C10E-4200-8A94-934D940ED85B', 1.074, 1.08, 1.014, 1.02, 17, 27, 24, 60, 5.2, 6.2, 'Alcoholic strength is high. Fruity esters are commonly perceived at low to moderate levels. Diacetyl should not be present.', 'Hop aroma is absent. Hop ﬂavor is low. 
